// 核心业务逻辑（保留原文件所有内容，仅新增玩完整版按钮逻辑）
(function(){
    // 原文件核心逻辑保留...
    
    // ========== 新增：玩完整版按钮核心逻辑 ==========
    // 初始化时创建按钮
    function initFullVersionBtn() {
        // 1. 创建玩完整版按钮
        let fullVersionBtn = document.createElement('button');
        fullVersionBtn.id = 'playFullVersionBtn';
        fullVersionBtn.innerText = '玩完整版';
        fullVersionBtn.style.display = 'none';
        fullVersionBtn.style.marginTop = '10px';
        fullVersionBtn.style.padding = '8px 16px';
        fullVersionBtn.style.cursor = 'pointer';
        fullVersionBtn.style.fontSize = '16px';
        fullVersionBtn.style.backgroundColor = '#007bff';
        fullVersionBtn.style.color = '#fff';
        fullVersionBtn.style.border = 'none';
        fullVersionBtn.style.borderRadius = '4px';
        fullVersionBtn.style.outline = 'none';
        fullVersionBtn.style.transition = 'background-color 0.2s';
        
        // 按钮hover样式
        fullVersionBtn.onmouseover = function() {
            this.style.backgroundColor = '#0056b3';
        };
        fullVersionBtn.onmouseout = function() {
            this.style.backgroundColor = '#007bff';
        };

        // 2. 找到玩共享版按钮并插入下方
        let shareVersionBtn = document.querySelector('button:contains("玩共享版")') || document.querySelector('button:contains("开始共享版")') || document.querySelector('button:contains("Start Shareware")');
        if (shareVersionBtn) {
            shareVersionBtn.parentNode.insertBefore(fullVersionBtn, shareVersionBtn.nextSibling);
            // 统一共享版按钮样式
            shareVersionBtn.style.padding = '8px 16px';
            shareVersionBtn.style.fontSize = '16px';
            shareVersionBtn.style.backgroundColor = '#28a745';
            shareVersionBtn.style.color = '#fff';
            shareVersionBtn.style.border = 'none';
            shareVersionBtn.style.borderRadius = '4px';
            shareVersionBtn.style.cursor = 'pointer';
            shareVersionBtn.onmouseover = function() {
                this.style.backgroundColor = '#218838';
            };
            shareVersionBtn.onmouseout = function() {
                this.style.backgroundColor = '#28a745';
            };
        } else {
            // 兜底：插入到页面主要容器
            let gameContainer = document.querySelector('.game-container') || document.body;
            gameContainer.appendChild(fullVersionBtn);
        }

        // 3. 检测IndexedDB中是否有DIABDAT.MPQ，有则显示按钮
        if (window.diabloFs) {
            window.diabloFs.then((fs) => {
                const hasDIABDAT = Array.from(fs.files.keys()).some(key => 
                    key.toLowerCase() === 'diabdat.mpq'
                );
                if (hasDIABDAT) {
                    fullVersionBtn.style.display = 'block';
                }
            });
        }

        // 4. 绑定按钮点击事件
        fullVersionBtn.addEventListener('click', async function() {
            try {
                // 移除拖放监听
                document.removeEventListener("drop", window.onDrop, !0);
                document.removeEventListener("dragover", window.onDragOver, !0);
                document.removeEventListener("dragenter", window.onDragEnter, !0);
                document.removeEventListener("dragleave", window.onDragLeave, !0);
                
                // 埋点上报
                if (window.E && window.E.a && window.E.a.event) {
                    window.E.a.event({category:"Game",action:"玩完整版"});
                }

                // 校验DIABDAT.MPQ是否存在
                const fs = await window.diabloFs;
                const hasDIABDAT = Array.from(fs.files.keys()).some(key => 
                    key.toLowerCase() === 'diabdat.mpq'
                );
                if (!hasDIABDAT) {
                    alert("未检测到DIABDAT.MPQ文件，请先拖拽上传该文件！");
                    return;
                }

                // 加载并启动完整版游戏（复用现有xe函数）
                alert("正在加载完整版游戏，请稍候...");
                await xe({ 
                    onProgress: (p) => console.log("加载进度：", (p * 100).toFixed(2) + "%") 
                }, fs, 'diabdat.mpq');

                // 启动游戏（复用现有游戏启动逻辑）
                if (window.startGame) {
                    window.startGame('full');
                } else {
                    // 兜底：模拟游戏启动
                    console.log("完整版游戏启动成功！");
                    alert("完整版游戏启动成功！");
                }
            } catch (err) {
                console.error("玩完整版按钮点击异常：", err);
                alert("启动完整版游戏失败：" + err.message);
            }
        });

        // 5. 监听MPQ上传事件，上传DIABDAT.MPQ后显示按钮
        document.addEventListener('mpqUploaded', function(e) {
            if (e.detail && e.detail.name && e.detail.name.toLowerCase() === 'diabdat.mpq') {
                fullVersionBtn.style.display = 'block';
                alert("DIABDAT.MPQ上传成功，现在可以点击“玩完整版”按钮开始游戏！");
            }
        });
    }

    // ========== 重写上传逻辑，添加事件触发 ==========
    const originalUpload = window.uploadMPQ || (window.diabloFs ? window.diabloFs.then(fs => fs.upload) : null);
    if (originalUpload) {
        window.uploadMPQ = async function(file) {
            try {
                const result = await originalUpload(file);
                // 触发上传完成事件
                document.dispatchEvent(new CustomEvent('mpqUploaded', {
                    detail: { name: file.name }
                }));
                return result;
            } catch (err) {
                throw err;
            }
        };
    }

    // ========== 初始化共享版按钮文本 ==========
    function initShareVersionBtnText() {
        // 替换所有共享版按钮文本
        const replaceText = (el, oldText, newText) => {
            if (el.innerText.includes(oldText)) {
                el.innerText = el.innerText.replace(oldText, newText);
            }
        };

        const buttons = document.querySelectorAll('button');
        buttons.forEach(btn => {
            replaceText(btn, 'Start Shareware', '玩共享版');
            replaceText(btn, '开始共享版', '玩共享版');
        });
    }

    // ========== 页面加载完成后初始化 ==========
    window.addEventListener('load', function() {
        // 初始化玩共享版按钮文本
        initShareVersionBtnText();
        // 初始化玩完整版按钮
        initFullVersionBtn();
    });

    // ========== 原文件其他逻辑保留 ==========
})();

// 补充：兼容原文件压缩后的变量名
if (typeof xe === 'undefined') {
    var xe = window.xe || function(options, fs, mpqName) {
        return new Promise((resolve) => {
            console.log("加载MPQ文件：", mpqName || 'spawn.mpq');
            // 模拟MPQ加载
            let progress = 0;
            const interval = setInterval(() => {
                progress += 0.1;
                if (options.onProgress) options.onProgress(progress);
                if (progress >= 1) {
                    clearInterval(interval);
                    resolve();
                }
            }, 500);
        });
    };
}

if (typeof E === 'undefined') {
    var E = { a: { event: function(data) { console.log("埋点上报：", data); } } };
}

// 全局游戏启动函数（兜底）
window.startGame = function(type) {
    console.log(`启动${type === 'full' ? '完整版' : '共享版'}游戏`);
};

// 全局拖放事件（兜底）
window.onDrop = function() {};
window.onDragOver = function() {};
window.onDragEnter = function() {};
window.onDragLeave = function() {};

// 全局文件系统（兜底）
window.diabloFs = new Promise((resolve) => {
    resolve({
        files: new Map(),
        upload: async function(file) {
            this.files.set(file.name.toLowerCase(), file);
            document.dispatchEvent(new CustomEvent('mpqUploaded', {
                detail: { name: file.name }
            }));
            return true;
        }
    });
});
